import { FieldValue, getFirestore } from "firebase-admin/firestore";
import { onDocumentUpdated } from "firebase-functions/v2/firestore";

export const miniLeagueOnUpdate = onDocumentUpdated(
  {
    database: "dev-database",
    document: "miniLeagues/{miniLeagueID}",
  },
  async (event) => {
    const before = event.data!.before.data();
    const after = event.data!.after.data();
    if (before.round === after.round) return null; // No relevant change

    const db = getFirestore("dev-database");

    const leagueID = event.params.miniLeagueID; // Same as League ID
    const leagueRef = db.collection("leagues").doc(leagueID);
    const leagueDoc = await leagueRef.get();
    if (!leagueDoc.exists) return null;

    const leagueData = leagueDoc.data()!;

    // Fetch all player data
    const playerRef = db.collection("players");

    const playerSnap = await playerRef.get();

    console.log("got players");

    const playerMap: Map<string, number> = new Map();

    playerSnap.forEach((doc) =>
      playerMap.set(doc.id, doc.data().points[leagueData.week]),
    );

    console.log("got playerMap");

    // Fetch all records from the league
    const records: {
      [key: string]: {
        wins: number;
        losses: number;
        ties: number;
      };
    } = {};

    leagueData.users.forEach((userID: string) => {
      const recordString = leagueData.record[userID] ?? "0-0-0";
      const recordArr = recordString.split("-");
      records[userID] = {
        wins: parseInt(recordArr[0]) ?? 0,
        losses: parseInt(recordArr[1]) ?? 0,
        ties: parseInt(recordArr[2]) ?? 0,
      };
    });

    // Fetch and Copy Rosters
    const userRosterIDMap = leagueData.rosters;
    const userRosterMap: {
      [key: string]: {
        batsmen: string[];
        bowlers: string[];
        allRounders: string[];
        wicketkeepers: string[];
        flex: string[];
        captain: string;
        vice_captain: string;
        ref: FirebaseFirestore.DocumentReference;
      };
    } = {};
    const leagueUpdates: { [key: string]: any } = {}; // Collect league updates here
    const rosterPromises: Promise<any>[] = [];

    const PLAYOFFS = 10;
    const playoffRound = after.round - PLAYOFFS;
    const playoffStarted = playoffRound >= 0; // fix this hardcoded value

    const batch = db.batch();

    for (const userID of Object.keys(userRosterIDMap)) {
      const lastRosterID =
        userRosterIDMap[userID][userRosterIDMap[userID].length - 1];
      const rosterRef = db.collection("rosters").doc(lastRosterID);
      console.log(lastRosterID);
      rosterPromises.push(
        rosterRef.get().then(async (rosterDoc) => {
          if (!rosterDoc.exists) return null; // Skip if roster doesn't exist

          console.log(rosterDoc.id);

          userRosterMap[userID] = {
            batsmen: rosterDoc.data()?.batsmen || [],
            bowlers: rosterDoc.data()?.bowlers || [],
            allRounders: rosterDoc.data()?.allRounders || [],
            wicketkeepers: rosterDoc.data()?.wicketkeepers || [],
            flex: rosterDoc.data()?.flex || [],
            captain: rosterDoc.data()?.captain || "",
            vice_captain: rosterDoc.data()?.vice_captain || "",
            ref: rosterRef,
          };

          // Copy Roster
          const newRosterRef = db.collection("rosters").doc();

          await Promise.all([
            newRosterRef.set({
              ...rosterDoc.data(),
              createdAt: FieldValue.serverTimestamp(),
            }),
            leagueRef.update({
              [`rosters.${userID}`]: FieldValue.arrayUnion(newRosterRef.id),
            }),
          ]);

          return null;
        }),
      );
    }

    // Wait for all roster copies to complete
    await Promise.all(rosterPromises);

    console.log("New Roster Copied");

    // Process Matchups
    const roundMatchup: { [key: string]: string } =
      leagueData.matchup[leagueData.week];

    const playoffPlayers = leagueData.playoffPlayers || [];

    if (!roundMatchup) return null; // Exit if no matchups for this round
    const seen = new Set<string>();

    for (const [user1, user2] of Object.entries(roundMatchup)) {
      if (user2 === "BYE") continue; // Skip BYE matchups
      if (!userRosterMap[user1] || !userRosterMap[user2]) continue; // Skip if user rosters are missing
      if (seen.has(user1) || seen.has(user2)) continue;
      seen.add(user1);
      seen.add(user2);

      // Calculate scores for both users
      const user1Score =
        calculateUserScore(userRosterMap[user1], playerMap) || 0; // Default to 0 if invalid
      const user2Score =
        calculateUserScore(userRosterMap[user2], playerMap) || 0;

      // Determine winner
      let winner = "";
      if (user1Score > user2Score) winner = user1;
      else if (user2Score > user1Score) winner = user2;

      // Update total scores:
      batch.update(userRosterMap[user1].ref, {
        editable: false,
        totalScore: FieldValue.increment(user1Score),
      });

      batch.update(userRosterMap[user2].ref, {
        editable: false,
        totalScore: FieldValue.increment(user1Score),
      });

      // Update records
      if (records[user1]) {
        records[user1].wins += winner === user1 ? 1 : 0;
        records[user1].losses += winner === user2 ? 1 : 0;
        records[user1].ties += winner === "" ? 1 : 0;
      } else {
        records[user1] = {
          wins: winner === user1 ? 1 : 0,
          losses: winner === user2 ? 1 : 0,
          ties: winner === "" ? 1 : 0,
        };
      }

      if (records[user2]) {
        records[user2].wins += winner === user2 ? 1 : 0;
        records[user2].losses += winner === user1 ? 1 : 0;
        records[user2].ties += winner === "" ? 1 : 0;
      } else {
        records[user2] = {
          wins: winner === user2 ? 1 : 0,
          losses: winner === user1 ? 1 : 0,
          ties: winner === "" ? 1 : 0,
        };
      }

      if (playoffRound > 0) {
        if (playoffPlayers.include(user1) && winner === user2) {
          playoffPlayers.remove(user1);
        }
        if (playoffPlayers.include(user2) && winner === user1) {
          playoffPlayers.remove(user2);
        }
      }
    }

    if (playoffRound > 0) {
      const playoffMatchup: { [key: string]: string } = {};
      for (let i = 0; i < playoffPlayers.length; i++) {
        playoffMatchup[playoffPlayers[i]] =
          i + 1 < playoffPlayers.length ? playoffPlayers[i + 1] : "BYE";
      }

      leagueUpdates[`matchup`] = FieldValue.arrayUnion(playoffMatchup);
      leagueUpdates[`playoffPlayers`] = playoffPlayers;
    }

    const record: { [key: string]: string } = {};
    const recordArray: {
      wins: number;
      losses: number;
      ties: number;
      id: string;
    }[] = [];

    for (const [key, value] of Object.entries(records)) {
      record[key] = `${value.wins}-${value.losses}-${value.ties}`;
      recordArray.push({
        wins: value.wins,
        losses: value.losses,
        ties: value.ties,
        id: key,
      });
    }

    leagueUpdates["record"] = record;

    console.log("update records and matchups");

    // Add round increment to league updates
    leagueUpdates["week"] = after.round;

    // Sort records by wins, losses, ties
    recordArray.sort((recordA, recordB) => {
      if (recordB.wins !== recordA.wins) {
        return recordA.wins - recordB.wins;
      }
      if (recordA.losses !== recordB.losses) {
        return recordB.losses - recordA.losses;
      }
      if (recordB.ties !== recordA.ties) {
        return recordB.ties - recordA.ties;
      }
      return 0;
    });

    leagueUpdates["waiverPriority"] = recordArray.map((val) => val.id);

    if (playoffRound === 0) {
      // Sort records by wins, losses, ties
      recordArray.sort((recordA, recordB) => {
        if (recordB.wins !== recordA.wins) {
          return recordB.wins - recordA.wins;
        }
        if (recordA.losses !== recordB.losses) {
          return recordA.losses - recordB.losses;
        }
        if (recordB.ties !== recordA.ties) {
          return recordA.ties - recordB.ties;
        }
        return 0;
      });

      const playoffCount = Math.min(4, recordArray.length); // fix 4 if needed

      for (let i = 0; i < playoffCount / 2; i++) {
        playoffPlayers.push(recordArray[i].id);
        if (playoffCount - 1 - i > i) {
          playoffPlayers.push(recordArray[playoffCount - 1 - i].id);
        }
      }

      const playoffMatchup: { [key: string]: string } = {};

      for (let i = 0; i < playoffPlayers.length; i++) {
        playoffMatchup[playoffPlayers[i]] =
          i + 1 < playoffPlayers.length ? playoffPlayers[i + 1] : "BYE";
      }

      leagueUpdates[`matchup`] = FieldValue.arrayUnion(playoffMatchup);
      leagueUpdates[`playoffPlayers`] = playoffPlayers;
    }

    // Commit all updates in a single batch
    batch.update(leagueRef, leagueUpdates);

    await batch.commit().catch((err) => {
      console.error(err);
    });

    return null;
  },
);

function calculateUserScore(
  {
    batsmen,
    bowlers,
    allRounders,
    wicketkeepers,
    flex,
    captain,
    vice_captain,
  }: {
    batsmen: string[];
    bowlers: string[];
    allRounders: string[];
    wicketkeepers: string[];
    flex: string[];
    captain: string;
    vice_captain: string;
  },
  playerMap: Map<string, number>,
): number {
  let score = 0;

  const captainMultiplier = 1;
  const viceCaptainMultiplier = 0.5;

  // Use playerMap to get player points
  batsmen.forEach((playerID) => {
    score += playerMap.get(playerID) || 0;
  });

  bowlers.forEach((playerID) => {
    score += playerMap.get(playerID) || 0;
  });

  allRounders.forEach((playerID) => {
    score += playerMap.get(playerID) || 0;
  });

  wicketkeepers.forEach((playerID) => {
    score += playerMap.get(playerID) || 0;
  });

  flex.forEach((playerID) => {
    score += playerMap.get(playerID) || 0;
  });

  // Add captain and vice captain points with multipliers
  score += (playerMap.get(captain) || 0) * captainMultiplier;
  score += (playerMap.get(vice_captain) || 0) * viceCaptainMultiplier;

  // Return total score
  return score;
}
