```ts
import { FieldValue, getFirestore } from "firebase-admin/firestore";
import { onDocumentUpdated } from "firebase-functions/v2/firestore";

export const miniLeagueOnUpdate = onDocumentUpdated(
  {
    database: "dev-database",
    document: "miniLeagues/{miniLeagueID}",
  },
  async (event) => {
    const before = event.data!.before.data();
    const after = event.data!.after.data();
    if (before.round === after.round) return null; // No relevant change

    const db = getFirestore("dev-database");

    const leagueID = event.params.miniLeagueID; // Same as League ID
    const leagueRef = db.collection("leagues").doc(leagueID);
    const leagueDoc = await leagueRef.get();
    if (!leagueDoc.exists) return null;

    const leagueData = leagueDoc.data()!;

    // Fetch all player data in a single read
    const playerSnap = await db.collection("players").get();
    const playerMap: Map<string, number> = new Map();
    playerSnap.forEach((doc) => playerMap.set(doc.id, doc.data().points[leagueData.week]));

    // Initialize records
    const records: { [key: string]: { wins: number; losses: number; ties: number } } = {};
    leagueData.users.forEach((userID: string) => {
      const recordString = leagueData.record[userID] ?? "0-0-0";
      const [wins, losses, ties] = recordString.split("-").map(Number);
      records[userID] = { wins, losses, ties };
    });

    // Fetch and copy rosters in a single batch read
    const userRosterIDMap = leagueData.rosters;
    const rosterRefs = Object.values(userRosterIDMap).flat().map((rosterID: string) => db.collection("rosters").doc(rosterID));
    const rosterDocs = await db.getAll(...rosterRefs);

    const userRosterMap: { [key: string]: any } = {};
    const batch = db.batch();

    rosterDocs.forEach((rosterDoc) => {
      if (!rosterDoc.exists) return;
      const rosterData = rosterDoc.data();
      const userID = Object.keys(userRosterIDMap).find((id) => userRosterIDMap[id].includes(rosterDoc.id));
      if (userID) {
        userRosterMap[userID] = { ...rosterData, ref: rosterDoc.ref };
        const newRosterRef = db.collection("rosters").doc();
        batch.set(newRosterRef, { ...rosterData, createdAt: FieldValue.serverTimestamp() });
        batch.update(leagueRef, { [`rosters.${userID}`]: FieldValue.arrayUnion(newRosterRef.id) });
      }
    });

    // Process matchups
    const roundMatchup = leagueData.matchup[leagueData.week];
    if (!roundMatchup) return null;

    const seen = new Set<string>();
    const playoffPlayers = leagueData.playoffPlayers || [];
    const PLAYOFFS = 10;
    const playoffRound = after.round - PLAYOFFS;
    const playoffStarted = playoffRound >= 0;

    for (const [user1, user2] of Object.entries(roundMatchup)) {
      if (user2 === "BYE" || seen.has(user1) || seen.has(user2)) continue;
      seen.add(user1);
      seen.add(user2);

      const user1Score = calculateUserScore(userRosterMap[user1], playerMap) || 0;
      const user2Score = calculateUserScore(userRosterMap[user2], playerMap) || 0;

      let winner = "";
      if (user1Score > user2Score) winner = user1;
      else if (user2Score > user1Score) winner = user2;

      batch.update(userRosterMap[user1].ref, { editable: false, totalScore: FieldValue.increment(user1Score) });
      batch.update(userRosterMap[user2].ref, { editable: false, totalScore: FieldValue.increment(user2Score) });

      updateRecords(records, user1, user2, winner);

      if (playoffRound > 0) {
        updatePlayoffPlayers(playoffPlayers, user1, user2, winner);
      }
    }

    if (playoffRound > 0) {
      const playoffMatchup = createPlayoffMatchup(playoffPlayers);
      batch.update(leagueRef, { matchup: FieldValue.arrayUnion(playoffMatchup), playoffPlayers });
    }

    const recordArray = createRecordArray(records);
    recordArray.sort(compareRecords);

    const leagueUpdates: { [key: string]: any } = {
      record: createRecordString(records),
      waiverPriority: recordArray.map((val) => val.id),
      week: after.round,
    };

    if (playoffRound === 0) {
      const playoffPlayers = selectPlayoffPlayers(recordArray);
      const playoffMatchup = createPlayoffMatchup(playoffPlayers);
      leagueUpdates.matchup = FieldValue.arrayUnion(playoffMatchup);
      leagueUpdates.playoffPlayers = playoffPlayers;
    }

    batch.update(leagueRef, leagueUpdates);
    await batch.commit().catch(console.error);

    return null;
  },
);

function calculateUserScore(roster: any, playerMap: Map<string, number>): number {
  const { batsmen, bowlers, allRounders, wicketkeepers, flex, captain, vice_captain } = roster;
  let score = 0;
  const captainMultiplier = 1;
  const viceCaptainMultiplier = 0.5;

  [batsmen, bowlers, allRounders, wicketkeepers, flex].forEach((group) => {
    group.forEach((playerID: string) => {
      score += playerMap.get(playerID) || 0;
    });
  });

  score += (playerMap.get(captain) || 0) * captainMultiplier;
  score += (playerMap.get(vice_captain) || 0) * viceCaptainMultiplier;

  return score;
}

function updateRecords(records: any, user1: string, user2: string, winner: string) {
  if (!records[user1]) records[user1] = { wins: 0, losses: 0, ties: 0 };
  if (!records[user2]) records[user2] = { wins: 0, losses: 0, ties: 0 };

  if (winner === user1) {
    records[user1].wins += 1;
    records[user2].losses += 1;
  } else if (winner === user2) {
    records[user2].wins += 1;
    records[user1].losses += 1;
  } else {
    records[user1].ties += 1;
    records[user2].ties += 1;
  }
}

function updatePlayoffPlayers(playoffPlayers: string[], user1: string, user2: string, winner: string) {
  if (winner && playoffPlayers.includes(user1) && winner === user2) {
    playoffPlayers.splice(playoffPlayers.indexOf(user1), 1);
  }
  if (winner && playoffPlayers.includes(user2) && winner === user1) {
    playoffPlayers.splice(playoffPlayers.indexOf(user2), 1);
  }
}

function createPlayoffMatchup(playoffPlayers: string[]): { [key: string]: string } {
  const playoffMatchup: { [key: string]: string } = {};
  for (let i = 0; i < playoffPlayers.length; i++) {
    playoffMatchup[playoffPlayers[i]] = i + 1 < playoffPlayers.length ? playoffPlayers[i + 1] : "BYE";
  }
  return playoffMatchup;
}

function createRecordArray(records: any): { wins: number; losses: number; ties: number; id: string }[] {
  return Object.entries(records).map(([id, record]) => ({ ...record, id }));
}

function compareRecords(recordA: any, recordB: any): number {
  if (recordB.wins !== recordA.wins) return recordB.wins - recordA.wins;
  if (recordA.losses !== recordB.losses) return recordA.losses - recordB.losses;
  return recordB.ties - recordA.ties;
}

function createRecordString(records: any): { [key: string]: string } {
  const record: { [key: string]: string } = {};
  for (const [key, value] of Object.entries(records)) {
    record[key] = `${value.wins}-${value.losses}-${value.ties}`;
  }
  return record;
}

function selectPlayoffPlayers(recordArray: any[]): string[] {
  const playoffCount = Math.min(4, recordArray.length);
  const playoffPlayers: string[] = [];
  for (let i = 0; i < playoffCount / 2; i++) {
    playoffPlayers.push(recordArray[i].id);
    if (playoffCount - 1 - i > i) {
      playoffPlayers.push(recordArray[playoffCount - 1 - i].id);
    }
  }
  return playoffPlayers;
}
```

### Key Optimizations

1. **Batch Reads**:
   - Fetch all player data and rosters in a single batch read to minimize the number of network calls.

2. **Batch Writes**:
   - Use a Firestore batch to perform all writes in a single network call.

3. **Avoid Redundant Reads**:
   - Cache the roster data locally to avoid fetching the same document multiple times.

4. **Efficient Data Structures**:
   - Use maps and sets for efficient lookups and updates.

5. **Transaction for Atomic Operations**:
   - Although not explicitly shown here, consider using Firestore transactions for operations that require atomicity.

